import"../chunks/DsnmJJEf.js";import"../chunks/CyPCCCDv.js";import{n as t,o,q as a}from"../chunks/B8uje50n.js";var n=o('<h1 id="item-displays">Item Displays</h1> <p>Item Displays render a vanilla Minecraft item model in the world. They can be animated just like <a href="/docs/nodes/groups">Groups</a> - position, rotation, and scale keyframes are all supported.</p> <img src="/images/docs/nodes/item-displays/example1.png" alt="Item Display example"/> <h2 id="element-options">Element Options</h2> <ul><li><h4 id="displayed-item">Displayed Item</h4> <p>The namespaced ID of the item to display (e.g. <code>minecraft:diamond_sword</code>, <code>minecraft:oak_log</code>).</p> <p>The item is validated against the Minecraft item registry for the selected target version. Invalid items are highlighted with a warning.</p></li> <li><h4 id="item-display-mode">Item Display Mode</h4> <p>Controls how the item model is oriented for display. This corresponds to Minecraft’s <code>item_display</code> NBT field.</p> <ul><li><code>none</code> — Default orientation.</li> <li><code>thirdperson_righthand</code> / <code>thirdperson_lefthand</code> — Third-person hand display orientation.</li> <li><code>firstperson_righthand</code> / <code>firstperson_lefthand</code> — First-person hand display orientation.</li> <li><code>head</code> — Head slot display orientation.</li> <li><code>gui</code> — GUI inventory display orientation.</li> <li><code>ground</code> — Ground (dropped item) display orientation.</li> <li><code>fixed</code> — Fixed display orientation (item frame).</li></ul></li></ul> <h2 id="entity-creation">Entity Creation</h2> <p>An Item Display always creates a <code>minecraft:item_display</code> entity when exported.</p> <h2 id="display-entity-config">Display Entity Config</h2> <p>Right-click on an Item Display node in the outliner and select <strong>Display Entity Config</strong> to open its configuration.</p> <p>See <a href="/docs/configs/display-entity">Configs / Display Entity</a>.</p>',1);function r(e){var i=n();a(18),t(e,i)}export{r as component};
